import{_ as a,c as e,o as l,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"技能管理: 查詢可用技能 | opencode-agent-skills","description":"學習 get_available_skills 工具的使用方法。透過搜尋、命名空間和過濾快速定位技能，掌握技能發現和管理的核心功能。","frontmatter":{"title":"技能管理: 查詢可用技能 | opencode-agent-skills","sidebarTitle":"快速找技能","subtitle":"技能管理: 查詢可用技能","description":"學習 get_available_skills 工具的使用方法。透過搜尋、命名空間和過濾快速定位技能，掌握技能發現和管理的核心功能。","tags":["技能管理","工具使用","命名空間"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),i={name:"zh-tw/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function t(p,s,o,c,d,r){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="查詢和列出可用技能" tabindex="-1">查詢和列出可用技能 <a class="header-anchor" href="#查詢和列出可用技能" aria-label="Permalink to &quot;查詢和列出可用技能&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>使用 <code>get_available_skills</code> 工具列出所有可用技能</li><li>透過搜尋查詢過濾特定技能</li><li>使用命名空間（如 <code>project:skill-name</code>）精確定位技能</li><li>識別技能來源和可執行腳本清單</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你想使用某個技能，但記不清它的確切名稱。也許你知道它是專案裡的某個技能，但不知道在哪個發現路徑下。或者你只是想快速瀏覽一下當前專案有哪些技能可用。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li><strong>探索新專案</strong>：加入一個新專案時，快速了解有哪些可用的技能</li><li><strong>技能名稱不確定</strong>：只記得技能的部分名稱或描述，需要模糊匹配</li><li><strong>多命名空間衝突</strong>：專案級和使用者級有同名技能，需要明確指定使用哪個</li><li><strong>查找腳本</strong>：想知道技能目錄下有哪些可執行的自動化腳本</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><code>get_available_skills</code> 工具幫你查看當前會話可用的所有技能。外掛會自動從 6 個發現路徑掃描技能：</p><div class="info custom-block"><p class="custom-block-title">技能發現優先順序</p><ol><li><code>.opencode/skills/</code> (專案級 OpenCode)</li><li><code>.claude/skills/</code> (專案級 Claude)</li><li><code>~/.config/opencode/skills/</code> (使用者級 OpenCode)</li><li><code>~/.claude/skills/</code> (使用者級 Claude)</li><li><code>~/.claude/plugins/cache/</code> (外掛快取)</li><li><code>~/.claude/plugins/marketplaces/</code> (已安裝外掛)</li></ol></div><p>同名技能按優先順序只保留第一個，後續的被忽略。</p><p>工具返回的資訊包括：</p><ul><li><strong>技能名稱</strong></li><li><strong>來源標籤</strong>（project、user、claude-project 等）</li><li><strong>描述</strong></li><li><strong>可執行腳本清單</strong>（如果有）</li></ul><div class="tip custom-block"><p class="custom-block-title">命名空間語法</p><p>你可以用 <code>namespace:skill-name</code> 格式明確指定來源：</p><ul><li><code>project:my-skill</code> - 使用專案級 OpenCode 技能（<code>.opencode/skills/</code>）</li><li><code>claude-project:my-skill</code> - 使用專案級 Claude 技能（<code>.claude/skills/</code>）</li><li><code>user:my-skill</code> - 使用使用者級 OpenCode 技能（<code>~/.config/opencode/skills/</code>）</li><li><code>claude-user:my-skill</code> - 使用使用者級 Claude 技能（<code>~/.claude/skills/</code>）</li><li><code>claude-plugins:my-skill</code> - 使用 Claude 外掛中的技能</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-列出所有可用技能" tabindex="-1">第 1 步：列出所有可用技能 <a class="header-anchor" href="#第-1-步-列出所有可用技能" aria-label="Permalink to &quot;第 1 步：列出所有可用技能&quot;">​</a></h3><p>在 OpenCode 中直接讓 AI 列出技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>列出所有可用的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git 操作和分支管理助手 [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  單元測試和覆蓋率分析工具</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  完整的軟體開發工作流程</span></span></code></pre></div><p><strong>你應該看到</strong>：一個技能清單，每個技能顯示名稱、來源標籤、描述和腳本清單。</p><h3 id="第-2-步-使用搜尋查詢過濾" tabindex="-1">第 2 步：使用搜尋查詢過濾 <a class="header-anchor" href="#第-2-步-使用搜尋查詢過濾" aria-label="Permalink to &quot;第 2 步：使用搜尋查詢過濾&quot;">​</a></h3><p>如果你只記得技能的部分名稱：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>查找包含 &quot;docker&quot; 的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>搜尋會匹配技能名稱和描述中的關鍵字，支援 <code>*</code> 萬用字元：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>查找以 &quot;test&quot; 開頭的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  單元測試和覆蓋率分析工具</span></span></code></pre></div><p><strong>你應該看到</strong>：只顯示符合查詢條件的技能。</p><h3 id="第-3-步-體驗模糊匹配建議" tabindex="-1">第 3 步：體驗模糊匹配建議 <a class="header-anchor" href="#第-3-步-體驗模糊匹配建議" aria-label="Permalink to &quot;第 3 步：體驗模糊匹配建議&quot;">​</a></h3><p>如果你輸入了錯誤的技能名稱：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>我想用 docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>外掛會基於 Levenshtein 距離計算相似度，自動建議最接近的技能名稱。</p><p><strong>你應該看到</strong>：錯誤提示和正確的技能建議。</p><h3 id="第-4-步-使用命名空間精確定位" tabindex="-1">第 4 步：使用命名空間精確定位 <a class="header-anchor" href="#第-4-步-使用命名空間精確定位" aria-label="Permalink to &quot;第 4 步：使用命名空間精確定位&quot;">​</a></h3><p>假設專案級和使用者級都有名為 <code>build-helper</code> 的技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>列出 build-helper 的詳細資訊</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  專案特定的建構配置和編譯優化 [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>如果使用者想要使用者級的技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>使用 user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  通用建構工具鏈和持續整合配置 [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>你應該看到</strong>：透過命名空間前綴可以存取不同來源的同名技能。</p><h3 id="第-5-步-檢查可執行腳本" tabindex="-1">第 5 步：檢查可執行腳本 <a class="header-anchor" href="#第-5-步-檢查可執行腳本" aria-label="Permalink to &quot;第 5 步：檢查可執行腳本&quot;">​</a></h3><p>查看技能目錄下有哪些腳本：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者輸入：</span></span>
<span class="line"><span>docker-helper 有哪些腳本？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系統回應：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>腳本會顯示在技能資訊的方括號中，用逗號分隔。你可以用 <code>run_skill_script</code> 工具執行這些腳本。</p><p><strong>你應該看到</strong>：技能名稱後面跟著 <code>[scripts: 腳本路徑1, 腳本路徑2, ...]</code> 格式的清單。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 你能列出所有可用的技能嗎？</li><li>[ ] 你能用搜尋查詢過濾特定技能嗎？</li><li>[ ] 你能理解技能來源標籤的含義嗎（project、user、claude-project 等）？</li><li>[ ] 你能說出技能命名空間的作用和語法嗎？</li><li>[ ] 你能從技能資訊中識別可執行腳本清單嗎？</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="陷阱-1-同名技能的覆蓋" tabindex="-1">陷阱 1：同名技能的覆蓋 <a class="header-anchor" href="#陷阱-1-同名技能的覆蓋" aria-label="Permalink to &quot;陷阱 1：同名技能的覆蓋&quot;">​</a></h3><p>如果專案級和使用者級有同名技能，你可能會困惑為什麼載入的不是你期望的技能。</p><p><strong>原因</strong>：技能按優先順序發現，專案級優先於使用者級，同名只保留第一個。</p><p><strong>解決</strong>：使用命名空間明確指定，如 <code>user:my-skill</code> 而不是 <code>my-skill</code>。</p><h3 id="陷阱-2-搜尋大小寫敏感" tabindex="-1">陷阱 2：搜尋大小寫敏感 <a class="header-anchor" href="#陷阱-2-搜尋大小寫敏感" aria-label="Permalink to &quot;陷阱 2：搜尋大小寫敏感&quot;">​</a></h3><p>搜尋查詢使用正則運算式，但設定了 <code>i</code> 標誌，所以是不區分大小寫的。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 這些搜尋是等效的</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="陷阱-3-萬用字元的轉義" tabindex="-1">陷阱 3：萬用字元的轉義 <a class="header-anchor" href="#陷阱-3-萬用字元的轉義" aria-label="Permalink to &quot;陷阱 3：萬用字元的轉義&quot;">​</a></h3><p>搜尋中的 <code>*</code> 會自動轉換為 <code>.*</code> 正則運算式，不需要手動轉義：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 搜尋以 &quot;test&quot; 開頭的技能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等同於正則運算式 /test.*/i</span></span></code></pre></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p><code>get_available_skills</code> 是探索技能生態的工具，支援：</p><ul><li><strong>列出所有技能</strong>：不加參數呼叫</li><li><strong>搜尋過濾</strong>：透過 <code>query</code> 參數符合名稱和描述</li><li><strong>命名空間</strong>：用 <code>namespace:skill-name</code> 精確定位</li><li><strong>模糊匹配建議</strong>：拼字錯誤時自動提示正確名稱</li><li><strong>腳本清單</strong>：顯示可執行的自動化腳本</li></ul><p>外掛會在會話開始時自動注入技能清單，所以你通常不需要手動呼叫這個工具。但在以下場景下它很有用：</p><ul><li>想快速瀏覽可用技能</li><li>記不清技能的確切名稱</li><li>需要區分同名技能的不同來源</li><li>想查看某個技能的腳本清單</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../loading-skills-into-context/">載入技能到會話上下文</a></strong>。</p><p>你會學到：</p><ul><li>使用 use_skill 工具載入技能到當前會話</li><li>理解技能內容如何以 XML 格式注入到上下文</li><li>掌握 Synthetic Message Injection 机制（synthetic 訊息注入）</li><li>了解技能在會話壓縮後如何保持可用</li></ul></blockquote><hr><h2 id="附錄-源碼參考" tabindex="-1">附錄：源碼參考 <a class="header-anchor" href="#附錄-源碼參考" aria-label="Permalink to &quot;附錄：源碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看源碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>GetAvailableSkills 工具定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills 函數</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill 函數</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch 函數</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>關鍵類型</strong>：</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>：技能來源標籤列舉</li></ul><p><strong>關鍵常量</strong>：</p><ul><li>模糊匹配閾值：<code>0.4</code>（<code>utils.ts:124</code>）- 相似度低於此值不返回建議</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>GetAvailableSkills()</code>：返回格式化的技能清單，支援查詢過濾和模糊匹配建議</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>：支援 <code>namespace:skill-name</code> 格式的技能解析</li><li><code>findClosestMatch(input: string, candidates: string[])</code>：基於多種匹配策略（前綴、包含、編輯距離）計算最佳匹配</li></ul><p><strong>業務規則</strong>：</p><ul><li>同名技能按發現順序去重，僅保留第一個（<code>skills.ts:258</code>）</li><li>搜尋查詢支援萬用字元 <code>*</code>，自動轉換為正則運算式（<code>tools.ts:43</code>）</li><li>模糊匹配建議只在有查詢參數且無結果時觸發（<code>tools.ts:49-57</code>）</li></ul></details>`,64)])])}const k=a(i,[["render",t]]);export{u as __pageData,k as default};
